protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    // HasIndex removed: Cosmos DB indexing is managed via the container's indexing policy,
    // not EF Core. EF Core 9 now throws if HasIndex is called on a Cosmos entity.

    modelBuilder.Entity<Product>().ToContainer("Products");

    // Preserve EF Core 8 discriminator property name ("Discriminator" → "$type" in EF Core 9).
    // Existing documents and direct SQL queries reference c.Discriminator.
    modelBuilder.Entity<Product>().HasDiscriminator<string>("Discriminator");

    // Preserve EF Core 8 compound id format ("Product|123") so existing documents
    // remain accessible. EF Core 9 defaults to key-only ids ("123").
    modelBuilder.Entity<Product>().HasRootDiscriminatorInJsonId(true);
}

